              <span className="font-semibold text-foreground">4.9/5 Rating</span>
            </div>
            <div className="flex items-center gap-2 bg-white/80 backdrop-blur-sm px-4 py-2 rounded-full shadow-lg">
              <Users className="h-5 w-5 text-primary" />
